import{_ as a,o as t,c as n,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Oracle Responsys Configuration","description":"","frontmatter":{"title":"Oracle Responsys Configuration","slug":"oracle-responsys-configuration"},"headers":[],"relativePath":"developer-hub/oracle-responsys-configuration.md","filePath":"developer-hub/oracle-responsys-configuration.md"}'),i={name:"developer-hub/oracle-responsys-configuration.md"};function s(r,e,l,p,c,d){return t(),n("div",null,[...e[0]||(e[0]=[o(`<h2 id="_1328" tabindex="-1">1328 <a class="header-anchor" href="#_1328" aria-label="Permalink to &quot;1328&quot;">​</a></h2><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Design and launch contextually relevant digital marketing campaigns to reach every consumer. Oracle Responsys helps you manage, personalize, and orchestrate interactions across all channels to deliver timely, helpful messages in the moments that matter—all without code, complex technical training, or reliance on other experts.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li><p>User clicks on a link in an email from their mobile mail client (Gmail, Apple Mail, etc.)</p></li><li><p>If the user has the app installed and the link has a corresponding screen in the app, the app will open and deep link the user to the right content.</p><ul><li>Ex. Product detail page, category shopping page, etc.</li></ul></li><li><p>If the user does not have the app installed or the link only corresponds to a screen on the web, the user is routed to the website using their default mobile web browser.</p><ul><li>Ex. Unsubscribe link, privacy policy, etc.</li></ul></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Required Roles</p><p>Branch&#39;s Branch Email requires the following roles involved in order to enable:</p><ul><li>Developers</li><li>CRM/Email Team</li><li>Oracle Responsys Account Manager / Support Team</li></ul></div><p>In order to enable Responsys, you must first:</p><ol><li><p>Have admin access to your <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Have Branch&#39;s Engagement <a href="./packaging.html">product</a> enabled for your Branch Account.</p></li><li><p>Implement the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><p>Set Up Deep Link Routing. How your mobile app routes to in-app content will determine how you will create and tag your Branch Links.</p><ul><li><a href="./in-app-routing.html#option-1-build-custom-routing-inside-the-routing-callback">Build custom routing inside the routing callback</a></li><li><a href="./in-app-routing.html#option-2-let-branch-use-your-existing-deep-link-routing">Let Branch use your existing deep link routing</a></li></ul></li><li><p><a href="./track-branch-events.html">Track events</a></p></li></ul></li><li><p>Review our <a href="./email-overview.html">Email Overview</a> and <a href="./email-integration-guide.html">Basic Email Integration Guide</a> to understand the feature and our integrations.</p></li><li><p>Obtain or set up your Responsys <strong>Click Tracking Domain</strong> (CTD). Reach out to your Responsys account manager for assistance on this.</p><ul><li>A Click Tracking Domain allows you to track engagement on email opoens and link clicks.</li><li>Your Responsys CTD must be <code>https</code> i.e. it needs to have a secure SSL certificate to meet Apple&#39;s apple-app-site-association (AASA) file requirements.</li></ul></li></ol><h2 id="enable-oracle-responsys" tabindex="-1">Enable Oracle Responsys <a class="header-anchor" href="#enable-oracle-responsys" aria-label="Permalink to &quot;Enable Oracle Responsys&quot;">​</a></h2><h3 id="_1-connect-oracle-responsys-service-in-branch" tabindex="-1">1. Connect Oracle Responsys Service in Branch <a class="header-anchor" href="#_1-connect-oracle-responsys-service-in-branch" aria-label="Permalink to &quot;1. Connect Oracle Responsys Service in Branch&quot;">​</a></h3><p>In the Branch Dashboard in Email → <a href="https://dashboard.branch.io/email/manager" target="_blank" rel="noreferrer">Manager tab</a>, find <strong>Oracle Responsys</strong> and click <strong>Enable</strong></p><p><em>[Image: 1428]</em>.gif &quot;3b8ad86-oracle-responsys-enable.gif&quot;)</p><h4 id="input-click-tracking-domain" tabindex="-1">Input Click Tracking Domain <a class="header-anchor" href="#input-click-tracking-domain" aria-label="Permalink to &quot;Input Click Tracking Domain&quot;">​</a></h4><p>Additionally, Responsys hosts the AASA file for your click tracking domain. You can provide your <strong>Responsys account manager&#39;s email</strong> for Branch to send the AASA file.</p><p>Input your Responsys CTD into the domain field and click the <strong>Save</strong> button.</p><ul><li><strong>Do not</strong> include <code>https://</code> when adding your CTD.</li></ul><div class="warning custom-block"><p class="custom-block-title">Click Tracking Domain</p><ul><li>Never add the same CTD to both your <strong>Live</strong> and <strong>Test</strong> Branch environments.</li><li>You can enable the integration with multiple CTDs, if needed, but you <strong>cannot</strong> add the same CTD to multiple Branch Dashboards or ESP integrations.</li></ul></div><h4 id="host-aasa-file" tabindex="-1">Host AASA File <a class="header-anchor" href="#host-aasa-file" aria-label="Permalink to &quot;Host AASA File&quot;">​</a></h4><p>Responsys will be the provider that hosts the AASA file. For this, reach out to your Oracle Account Manager or Support team to open a Support Request (SR) ticket to host the AASA file on the CTD.</p><p>Once you&#39;ve entered your CTD, you should be able to see what your AASA file looks like to send to Oracle by clicking the <strong>View AASA</strong> hyperlink below the <strong>Save</strong> button.</p><p>AASA Hosting Requirements:</p><ul><li>Served over HTTPS</li><li>Uses <code>application/json</code> MIME type</li><li>Does not have an appended <code>.json</code> to the apple-app-site-association file name</li><li>Has a size not exceeding 123 Kb (a requirement in iOS 9.3.1+)</li></ul><p>Example AASA File:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>    &quot;applinks&quot;: {</span></span>
<span class="line"><span>        &quot;apps&quot;: [],</span></span>
<span class="line"><span>        &quot;details&quot;: [</span></span>
<span class="line"><span>            {</span></span>
<span class="line"><span>                &quot;appID&quot;: &quot;TJV89Z7327.com.branch.enterprise.mobileapp&quot;,</span></span>
<span class="line"><span>                &quot;paths&quot;: [</span></span>
<span class="line"><span>                    &quot;/pub/acc*&quot;,</span></span>
<span class="line"><span>                    &quot;acc*&quot;</span></span>
<span class="line"><span>                ]</span></span>
<span class="line"><span>            },</span></span>
<span class="line"><span>            {</span></span>
<span class="line"><span>                &quot;appID&quot;: &quot;U33TFKH78H.com.branch.mobileapp&quot;,</span></span>
<span class="line"><span>                &quot;paths&quot;: [</span></span>
<span class="line"><span>                    &quot;/pub/acc*&quot;,</span></span>
<span class="line"><span>                    &quot;acc*&quot;</span></span>
<span class="line"><span>                ]</span></span>
<span class="line"><span>            }</span></span>
<span class="line"><span>        ]</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Verify</p><p>Use Branch&#39;s <a href="https://branch.io/resources/aasa-validator/" target="_blank" rel="noreferrer">AASA Validator</a> to verify that Oracle is hosting your AASA file correctly on your CTD.</p></div><h3 id="_2-configure-your-app" tabindex="-1">2. Configure your App <a class="header-anchor" href="#_2-configure-your-app" aria-label="Permalink to &quot;2. Configure your App&quot;">​</a></h3><h4 id="add-your-responsys-ctd-to-your-associated-domains" tabindex="-1">Add your Responsys CTD to your Associated Domains <a class="header-anchor" href="#add-your-responsys-ctd-to-your-associated-domains" aria-label="Permalink to &quot;Add your Responsys CTD to your Associated Domains&quot;">​</a></h4><p>For your iOS App, you must add the CTD to the Associated Domains. Additional details can be found <a href="./ios-basic-integration.html#8-add-esp-ctd-universal-email">here</a>.</p><p>.png &quot;Associated Domains.png&quot;)</p><h4 id="add-handle-web-only-content-app-code" tabindex="-1">Add Handle Web-Only Content App Code <a class="header-anchor" href="#add-handle-web-only-content-app-code" aria-label="Permalink to &quot;Add Handle Web-Only Content App Code&quot;">​</a></h4><p>If you have links to content that exist only on the web and not in the app (for example, a temporary marketing webpage that isn&#39;t in the app), then this code snippet will ensure all links that have not had deep linking script applied will open in a browser. Details can be found <a href="./ios-advanced-features.html#section-handle-links-for-web-only-content">here</a>.</p><h4 id="return-yes-to-continueuseractivity" tabindex="-1">Return <code>YES</code> to <code>continueUserActivity</code> <a class="header-anchor" href="#return-yes-to-continueuseractivity" aria-label="Permalink to &quot;Return \`YES\` to \`continueUserActivity\`&quot;">​</a></h4><p>Additionally, you will need to add the CTD to your iOS app&#39;s info.plist file. Additional details can be found <a href="./ios-advanced-features.html#return-yes-to-continueuseractivity">here</a>.</p><p>.png &quot;branch-universal-link-domain.png&quot;)</p><h3 id="_3-create-branch-links-for-your-emails" tabindex="-1">3. Create Branch Links for your Emails <a class="header-anchor" href="#_3-create-branch-links-for-your-emails" aria-label="Permalink to &quot;3. Create Branch Links for your Emails&quot;">​</a></h3><p>Before you start sending your email campaigns, you need to determine what flow you want the user to experience and flag your email links accordingly.</p><p>You will need to replace the web URLs in your email templates with Branch Links. There are a few different ways you can create Branch Links. Choose <strong>one</strong> of the following methods based on your current email marketing workflows:</p><table tabindex="0"><thead><tr><th>Method</th><th>Description</th><th>Recommendation</th></tr></thead><tbody><tr><td>Spreadsheet Formula Converter</td><td>Use a spreadsheet that contains a list of all of your email URLs used in your Responsys Link Tables to create a Branch <a href="./creating-a-deep-link.html#long-links">Long Link</a> that replaces your Link Table URLs.</td><td>Recommended if you are already using a spreadsheet to configure your email URLs for the Responsys Link Tables.</td></tr><tr><td>Script Upload</td><td>Create and upload a code snippet macro to programmatically create a Branch Link from an existing web link. Email Message Designer is required on your Responsys account.</td><td>Recommended if you are comfortable with setting up, configuring, and using scripts for Responsys Link Tables.</td></tr></tbody></table><h4 id="spreadsheet-formula-converter" tabindex="-1">Spreadsheet Formula Converter <a class="header-anchor" href="#spreadsheet-formula-converter" aria-label="Permalink to &quot;Spreadsheet Formula Converter&quot;">​</a></h4><p>This method assumes you are already using a spreadsheet to configure your email URLs. For this, you will create a Branch Link using a formula to convert a URL using the<code>CONCATENATE</code> method.</p><div class="info custom-block"><p class="custom-block-title">Query Parameters</p><p>The formula will be using query parameters to programmatically convert your email URLs into Branch Link Links while utilizing any other key/value pairs for analytics tracking and deep linking. You will need to identify the following:</p><ul><li>The original web URL to convert</li><li>The deep linking mechanism used by your mobile app</li><li>Any analytics paremeters you want to use for tracking (ex. campaign name)</li></ul></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=CONCATENATE(</span></span>
<span class="line"><span>	&quot;https://{BRANCH_LINK_DOMAIN}.app.link/3p?%243p=e_rs&amp;%24original_url=&quot;, {CELL_CONTAINING_WEB_URL},&quot;&amp;%24deeplink_path=&quot;, ENCODEURL({CELL_CONTAINING_URI_CELL}),</span></span>
<span class="line"><span>	“&amp;~campaign=”, ENCODEURL({CAMPAIGN_NAME_CELL}),</span></span>
<span class="line"><span>	“&amp;~channel=Email&quot;,</span></span>
<span class="line"><span>  &quot;&amp;~feature=&quot;, ENCODEURL({FEATURE_NAME_CELL})</span></span>
<span class="line"><span>)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>{BRANCH_LINK_DOMAIN}</code></td><td>Replace with your Branch Link Domain found <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">here</a>.</td></tr><tr><td><code>{CELL_CONTAINING_WEB_URL}</code></td><td>Replace with the cell in your spreadsheet that has the original web URL.</td></tr><tr><td><code>{CELL_CONTAINING_URI_CELL}</code></td><td>Replace with the cell in your spreadsheet that indicates the URI scheme used by your app to determine deep linked routing screen navigation. - Note: ⚠️ Do not include <code>&quot;&amp;%24deeplink_path=&quot;, ENCODEURL({CELL_CONTAINING_URI_CELL})</code> if your app is routing using web URLs. Only use for routing via URI schemes.</td></tr><tr><td><code>{CAMPAIGN_NAME_CELL}</code></td><td>Replace with the cell in your spreadsheet that indicates the name of the email campaign.</td></tr><tr><td><code>{FEATURE_NAME_CELL}</code></td><td>Replace with the cell in your spreadsheet that indicates the name of the feature (ex. app screen name).</td></tr></tbody></table><p>The final output should be a Branch Long Link that you use in your Responsys Link Tables. Add that Branch Link to the <strong>LINK_URL, IOS_LINK_URL, and ANDROID_LINK_URL</strong> fields of the Responsys Link Table</p><h4 id="script-upload" tabindex="-1">Script Upload <a class="header-anchor" href="#script-upload" aria-label="Permalink to &quot;Script Upload&quot;">​</a></h4><p>In this step, we&#39;ll upload a script that makes it very easy to create deep links in your emails. Please remember that this will require an EMD (Email Message Designer) enabled account.</p><ol><li>Work with your Branch account manager to modify the following code snippet, replacing <code>DOMAIN-HERE</code> with your Branch base domain:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;#macro deeplink link_to_be_wrapped&gt;&lt;#assign branch_base_url=&quot;https://DOMAIN-HERE/3p?%243p=e_rs&quot;&gt;&lt;#assign final_link=branch_base_url + &quot;&amp;%24original_url=&quot; + link_to_be_wrapped?url(&quot;ISO-8859-1&quot;)&gt;&lt;a href=&quot;\${final_link}&quot;&gt;&lt;#nested&gt;&lt;/a&gt;&lt;/#macro&gt; &lt;#macro tracked_deeplink link_to_be_wrapped&gt;&lt;#assign branch_base_url=&quot;https://DOMAIN-HERE/3p?%243p=e_rs&quot;&gt;&lt;#assign deeplink=branch_base_url + &quot;&amp;%24original_url=&quot; + link_to_be_wrapped?url(&quot;ISO-8859-1&quot;)&gt;&lt;/#macro&gt;</span></span></code></pre></div><ol start="2"><li><p>Log in to your Responsys account.</p></li><li><p>In the Responsys Dashboard, open your Content Library. You can also access it via the Shortcuts screen on the main page:</p></li><li><p>Once you are in the Content Manager, you’ll see a list of folders where content is stored. Under <strong>All Content</strong>, create a new folder named <code>Branch_SDK</code>:</p></li><li><p>Select the <strong>Branch_SDK</strong> folder and then click <strong>Create Document</strong>:</p></li><li><p>In the Create Document window:</p><ul><li>Enter <code>branch-sdk</code> in the “Document Name” field.</li><li>In the <strong>Content Box</strong>, delete all the text.</li><li>Paste the snippet you copied in <strong>1</strong>.</li><li>Click Save.</li></ul></li></ol><p>You have now successfully created the deep linking script. Your file structure should look as follows:</p><p><strong>Configure your Responsys email templates</strong></p><p>This code is referred to as the &quot;Branch script&quot; - this script will convert your web URLs to deep links.</p><p>The Responsys integration requires you to add email template code in two places.</p><ol><li>At the top of an email template</li><li>Immediately before a hyperlink</li></ol><p>Copy the following snippet, and using the “Source” view, paste the snippet directly under the <code>&lt;html&gt;</code> tag for every template you plan to add deep linking to.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;#include &quot;cms://contentlibrary/Branch_SDK/branch-sdk.htm&quot;&gt;</span></span></code></pre></div><p><strong>Configuring the Responsys Link Table</strong></p><p>For the Branch SDK to generate Branch Links in the email or the 3P links while redirections, the Link Tracking table for the email template should contain the following two LINK NAME with the <code>\${deeplink}</code> as the <strong>LINK URL</strong>.</p><p><em>For creating tracked links, ensure that</em> <em><strong>‘Track Link’</strong></em> <em>is set to</em> <em><strong>ON</strong></em>*. Tracked links will be generated under the Responsys Click Tracking Domain and will then redirect to a Branch 3p link (the link added as the base URL in the Branch_SDK.htm file.*</p><p><strong>Create deep links</strong></p><p>Wherever you are using <code>&lt;a&gt;</code> tags in your email templates, replace those with <code>&lt;@deeplink&gt;</code> tags, or add <code>&lt;@tracked_deeplink /&gt;</code> for web URLs that you would like to deep link.</p><p>Here&#39;s how it looks with Link Tracking disabled.</p><p><em>Before:</em><br><code>&lt;a href=&quot;https://branch.io&quot;&gt;Example link&lt;/a&gt;</code></p><p><em>After:</em><br><code>&lt;@deeplink &quot;https://branch.io&quot;&gt;Example link&lt;/@deeplink&gt;</code></p><p>With link tracking enabled, you can still use Branch Links in emails.</p><p><em>Before:</em><br><code>&lt;a href=&quot;https://branch.io/product/1234&quot;&gt;Example link&lt;/a&gt;</code></p><p><em>After:</em><br><code>&lt;@tracked_deeplink &quot;https://branch.io/product/1234&quot; /&gt; &lt;a href=&quot;\${clickthrough(&#39;TEST_TRACKED_DEEPLINK&#39; , &#39;deeplink=&#39; + deeplink)}&quot;&gt;Example link&lt;/a&gt;</code></p><h3 id="_4-handle-web-only-content" tabindex="-1">4. Handle Web-Only Content <a class="header-anchor" href="#_4-handle-web-only-content" aria-label="Permalink to &quot;4. Handle Web-Only Content&quot;">​</a></h3><p>In some cases you may have content on web that isn’t in the app - for example, a temporary Mother’s Day promotion or an unsubscribe button. You can designate links to only open on web if you use the Responsys Link Table feature. There are three URL fields in the link table when creating a new link: <code>LINK_URL</code>, <code>IOS_LINK_URL</code>, and <code>ANDROID_LINK_URL</code>. If you only enter the link in the <code>LINK_URL</code> field, the path of the final click-wrapped url will begin with <code>/pub/cc</code>. However, if you also input the same link in <code>IOS_LINK_URL</code>, then the path of the final click-wrapped url will begin with <code>pub/acc</code>. You should set up your AASA file to allow only the path <code>/pub/acc*</code> in order to not launch the app from web-only links.</p><h3 id="_5-view-analytics" tabindex="-1">5. View Analytics <a class="header-anchor" href="#_5-view-analytics" aria-label="Permalink to &quot;5. View Analytics&quot;">​</a></h3><p>Once completed and email campaigns are launched, you&#39;re ready to view data in the <a href="https://branch.dashboard.branch.io/email/activity" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p><h2 id="troubleshooting-and-extra-features" tabindex="-1">Troubleshooting and Extra Features <a class="header-anchor" href="#troubleshooting-and-extra-features" aria-label="Permalink to &quot;Troubleshooting and Extra Features&quot;">​</a></h2><h4 id="styling" tabindex="-1">Styling <a class="header-anchor" href="#styling" aria-label="Permalink to &quot;Styling&quot;">​</a></h4><p>If you include style tags within your <code>&lt;a&gt;</code> tags, you’ll need to separate those out into a separate div inside the <code>&lt;@deeplink&gt;</code> tag. If you use tracked links with <code>&lt;a&gt;</code> tags, those will work fine.</p><p>Style Tags within your anchor tags like so:</p><p>Before:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;a href=&quot;https://branch.io/&quot; style=&quot;color:#000001;text-decoration:none;&quot;&gt;Branch Website&lt;/a&gt;</span></span></code></pre></div><p>After:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;@deeplink &quot;https://branch.io/&quot;&gt;&lt;div style=&quot;color:#000001;text-decoration:none;&quot;&gt;Branch Website&lt;/div&gt;&lt;/@deeplink&gt;</span></span></code></pre></div><h4 id="launch-failed-error" tabindex="-1">Launch Failed Error <a class="header-anchor" href="#launch-failed-error" aria-label="Permalink to &quot;Launch Failed Error&quot;">​</a></h4><p>You’ll see this error if you haven’t included the <code>&lt;#import &gt;</code> snippet in your template.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Launch Failed: Launch failed: Template /contentlibrary/branch test campaign/My Default Template.htm caused an execution error: on line 183, column 92 in cms://contentlibrary/branch test campaign/Content.htm: deeplink is not a user-defined directive. It is a freemarker.template.SimpleScalar</span></span></code></pre></div><h4 id="using-dynamic-data-from-profile-extension-tables" tabindex="-1">Using dynamic data from profile extension tables <a class="header-anchor" href="#using-dynamic-data-from-profile-extension-tables" aria-label="Permalink to &quot;Using dynamic data from profile extension tables&quot;">​</a></h4><p>The <code>&lt;@deeplink &gt;</code> and <code>&lt;@tracked_deeplink /&gt;</code> tags even work with dynamic links injected via RPL.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;@deeplink &quot;\${latestProduct.url}&quot;&gt;\${latestProduct.name}&lt;/@deeplink&gt;</span></span></code></pre></div><h4 id="dynamic-query-parameters" tabindex="-1">Dynamic Query Parameters <a class="header-anchor" href="#dynamic-query-parameters" aria-label="Permalink to &quot;Dynamic Query Parameters&quot;">​</a></h4><p>Certain links in the Responsys Link Table use dynamic variables as query parameters.<br> Ex. ....com/?key=\${VALUE}<br> In some cases, the value parameter will require additional URI encoding in order for the final URL to be a valid link.</p>`,88)])])}const g=a(i,[["render",s]]);export{u as __pageData,g as default};
